  const startPos = bot.entity ? bot.entity.position.clone() : null;
  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) { return; }
    while (canContinueBotAction(bot, token)) {
      const hostiles = getHostiles();
      if (hostiles.length === 0) { return; }
      const nearest = hostiles[0];
      const nearestDistance = distance(bot.entity.position, nearest.position);
      if (nearestDistance >= args.preferredDistanceBlocks) { break; }
      if (startPos && horizontalDistance(bot.entity.position, startPos) >= args.maxRetreatDistanceBlocks) { break; }
      if (activeElapsedMs >= args.maxDurationTicks * 50) { break; }
      const dir = computeRetreatDirection(hostiles);
      const moveLook = bot.entity.position.offset(dir.x * 8, Math.max(1.4, (bot.entity.height || 1.8) * 0.75), dir.z * 8);
      if (!await waitUntilWorldActive(bot, token, pollMs)) { return; }
      try {
        await bot.lookAt(moveLook, true);
      } catch (err) {
      }
      bot.setControlState('back', false);
      bot.setControlState('left', false);
      bot.setControlState('right', false);
      bot.setControlState('forward', true);
      bot.setControlState('sprint', true);
      if (lastMeasurePos) {
        const moved = horizontalDistance(bot.entity.position, lastMeasurePos);
        if (moved < 0.04) {
          noProgressMs += pollMs;
        } else {
          noProgressMs = 0;
          lastMeasurePos = bot.entity.position.clone();
        }
      } else {
        lastMeasurePos = bot.entity.position.clone();
      }
      bot.setControlState('jump', noProgressMs > 250 || nearestDistance < 1.4);
      const shouldPlace = placedBlocks < args.maxBarrierBlocks && activeElapsedMs - lastPlaceMs >= 350 && (nearestDistance <= args.placeBarrierWhenHostileWithinBlocks || (nearestDistance <= args.preferredDistanceBlocks && isLineMostlyClear(nearest)));
      if (shouldPlace) {
        bot.setControlState('forward', false);
        bot.setControlState('sprint', false);
        if (!await waitUntilWorldActive(bot, token, pollMs)) { return; }
        const placed = await placeBarrierIfPossible(nearest);
        if (placed) {
          placedBlocks += 1;
          lastPlaceMs = activeElapsedMs;
        }
        const refreshed = getNearestHostile();
        if (refreshed) {
          try {
            await bot.lookAt(refreshed.position.offset(0, Math.max(0.6, (refreshed.height || 1.8) * 0.7), 0), true);
          } catch (err) {
          }
        }
      }
      if (nearestDistance < 1.15 && noProgressMs >= 400 && activeElapsedMs - lastAttackMs >= 800) {
        try {
          const weapon = findWeaponItem();
          if (weapon) { await bot.equip(weapon, 'hand'); }
          await bot.lookAt(nearest.position.offset(0, Math.max(0.6, (nearest.height || 1.8) * 0.7), 0), true);
          bot.attack(nearest);
          lastAttackMs = activeElapsedMs;
          noProgressMs = 0;
        } catch (err) {
        }
      }
      if (!await waitForActiveMs(bot, token, pollMs, pollMs)) { return; }
      activeElapsedMs += pollMs;
    }
    bot.clearControlStates();
    if (canContinueBotAction(bot, token) && bot.pathfinder) {
      const spot = findBestOpenSpot(3);
      if (spot && horizontalDistance(bot.entity.position, spot.offset(0.5, 0, 0.5)) > 1.2) {
        try {
          const movements = new Movements(bot);
          movements.canDig = false;
          bot.pathfinder.setMovements(movements);
          bot.pathfinder.setGoal(new goals.GoalNear(spot.x, spot.y, spot.z, 1));
          usedPathfinder = true;
          let settleMs = 0;
          while (canContinueBotAction(bot, token) && settleMs < 1500 && horizontalDistance(bot.entity.position, spot.offset(0.5, 0, 0.5)) > 1.4) {
            if (!await waitForActiveMs(bot, token, 100, pollMs)) { return; }
            settleMs += 100;
          }
        } catch (err) {
        }
      }
    }
  } finally {
    bot.clearControlStates();
    if (usedPathfinder && bot.pathfinder) {
      try { bot.pathfinder.setGoal(null); } catch (err) {}
      try { bot.pathfinder.stop(); } catch (err) {}
    }
  }
});
return '<STARTED>: Emergency retreat started from nearest hostile ' + initialTarget.id + (hadBarrierItem ? ' with barrier blocks available.' : ' without available barrier blocks.');
